const response = $input.first().json;

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Не удалось получить ответ от модели',
      raw: response
    }
  }];
}

// Убираем markdown обёртку если есть
let cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// Убираем <think>...</think> блоки если модель thinking
cleaned = cleaned.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Если не JSON — вернуть как текст
  return [{
    json: {
      success: true,
      raw_answer: content,
      parsed: false
    }
  }];
}

// Если массив — считаем итого
if (Array.isArray(parsed)) {
  const total = {
    calories: 0,
    protein: 0,
    carbs: 0,
    fats: 0
  };
  parsed.forEach(item => {
    total.calories += item.calories || 0;
    total.protein  += item.protein  || 0;
    total.carbs    += item.carbs    || 0;
    total.fats     += item.fats     || 0;
  });

  return [{
    json: {
      success: true,
      parsed: true,
      dishes: parsed,
      total: total
    }
  }];
}

return [{
  json: {
    success: true,
    parsed: true,
    dishes: [parsed],
    total: {
      calories: parsed.calories || 0,
      protein:  parsed.protein  || 0,
      carbs:    parsed.carbs    || 0,
      fats:     parsed.fats     || 0
    }
  }
}];

