// 3. Функция для вытаскивания значений из YAML-текста с помощью регулярных выражений
function extractYamlValue(text, key, isNumber = false) {
  const regex = new RegExp(`^${key}:\\s*"?([^"\\n]+)"?`, 'm');
  const match = text.match(regex);
  if (match && match[1]) {
    return isNumber ? parseFloat(match[1]) || 0 : match[1].trim();
  }
  return isNumber ? 0 : "";
}

